var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"크아악-! 아파, 아프다고, 메이슨 씨!","JPN":"くああっ！　痛い、痛いって、メイソンさん！","ENG":"Aaaargh! It hurts, Mr. Mason!","TWN":"呃啊啊–！好、好痛，梅森！"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"엄살 피우긴. 대령은 카일이나 실비아에 비하면 양호한 편이야.","JPN":"大袈裟な。大佐はカイルやシルビアに比べたらマシなほうなんだぞ。","ENG":"Quit whining. Compared to Kyle or Sylvia, you're getting off easy.","TWN":"少無病呻吟了，上校比起凱爾和希爾維亞還算好的了。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"애당초 대령 몸은 워낙 튼튼해서 이정도로는 안 죽는다고.","JPN":"そもそも、大佐の体は丈夫すぎてこの程度じゃ死なねえよ。","ENG":"With that ironclad body of yours, this much won't kill you anyway.","TWN":"你的身體本來就很健壯，這點程度不會死的。"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"죽는 게 아니라 아프다고! 사람이 말을 하면 좀 들어!","JPN":"死ぬんじゃなくて痛いって！　人の話を聞け！","ENG":"I'm not dying, I'm hurting! Try listening when a guy says something!","TWN":"不是會死而是會痛！拜託你聽聽別人說什麼！"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"후후. 역시 군인은 나약하군. 이런 작은 싸움에서 저런 부상이라니 말이야.","JPN":"ふふ。やっぱり軍人は弱いな。この規模の戦いであれだけ負傷するなんて。","ENG":"Haha. Soldiers are too soft. Taking wounds like that from a minor scrap.","TWN":"呵呵，軍人果然很脆弱，居然在這種小戰鬥受那種傷。"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"하하! 짬밥이나 먹는 녀석들이 힘을 쓰겠어?","JPN":"はは！　キャリア組は荒仕事しないからな！","ENG":"Haha! Chow-line grunts don't have real strength.","TWN":"哈哈！吃部隊伙食的傢伙能使得上力嗎？"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"아무렴. 몇 번이나 생사의 고비를 넘긴 우리 같은 용병들에겐 우스울 지경이지.","JPN":"ああ、何度も死線を超えてきた俺たち傭兵にとっては、こんな戦いなんてザラだよな。","ENG":"Right. For mercs like us who've cheated death a few times, this is laughable.","TWN":"想當然，對我們這種度過好幾次生死關頭的傭兵來說很可笑。"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"하하하!!","JPN":"ははは！！","ENG":"Hahaha!!","TWN":"哈哈哈！！"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"제길… 이건 부당해. 가장 힘든 임무를 맡은 내 취급이 왜 이런 식이냐고!","JPN":"くそ……理不尽だ。俺の任務が一番大変だったのに、扱いが雑すぎるんじゃないか！","ENG":"Damn it... this is unfair. Why am I getting treated like this when I was given the toughest job?!","TWN":"該死…這不公平，負責執行最艱難任務的我，為什麼會受到這種待遇！"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"그 말은 넘어가기 힘드네요. 작전팀 이외에도 다들 여러가지로 고생했다고요.","JPN":"その言葉は聞き捨てなりませんね。作戦チーム以外のみんなも色々と大変だったのに。","ENG":"Hard to let that slide. Folks outside the operations team busted their backs too.","TWN":"這話實在聽不下去，除了作戰組以外，大家也都吃了不少苦。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"침식체를 상대하는 게, 어쩌면 대피소 진상들을 상대하는 것보다 편하다는 걸 아셔야죠.","JPN":"侵食体と戦っている方が、避難所でクレーマーの相手をするよりは楽ってこともあるんですからね。","ENG":"Think fighting C.O.s is rough? Try babysitting a shelter full of whiners.","TWN":"你應該要知道，對付侵蝕體也許比對付避難所那些討厭的人還輕鬆。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"다들 기운을 차려서 다행이군.","JPN":"皆元気そうでなによりだ。","ENG":"I'm glad to see everyone getting their strength back.","TWN":"幸好大家都打起精神來了。"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"네. 다른 분들도 무사히 치료 중이라고 합니다.","JPN":"はい。他の方々も無事治療を受けているようです。","ENG":"Yes. The others are being treated safely as well.","TWN":"是，其他人也在順利接受治療中。"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"다만… 대균열을 막는 건 실패했으니, 도시가 붕괴되는 건 시간문제겠죠.","JPN":"ただ……大亀裂は止められなかったので、都市の崩壊は時間の問題でしょう。","ENG":"But... since we failed to halt the Grand Dimension Crevice, the city's collapse is a matter of time.","TWN":"但是…因為阻擋大峽谷失敗，所以城市早晚會崩壞。"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"당장은 인명피해를 줄인데 만족하지. 살아만 있으면 어떻게든 그 다음이 있는 법이니까.","JPN":"今は人的被害を抑えられたことに満足しよう。生きてさえいれば、次のチャンスはやってくるものだからな。","ENG":"For now, be satisfied we cut casualties. If you're alive, there's always another way next time.","TWN":"暫時減少人員傷亡已經很滿足了，只要能活下來，無論如何都會有下一次機會。"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"다만, 이곳에 마련될 나나하라 가문연합의 봉인역도 언젠간 제 힘을 다할 거야.","JPN":"だが、ここに設けられる七原家連合の封印域もいつか限界が来る。","ENG":"Still, the Domain the Nanahara Family Alliance set here will run out of power someday.","TWN":"但是，要在這裡設置的七原家族聯盟封印域總有一天力量也會用盡。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"준비했던 선로전환기 역시 지키지 못했고, 대균열의 뿌리는 멈추지 않을 테니…….","JPN":"用意した線路転換器も守れなかったし、大亀裂の根は止まらない……","ENG":"We couldn't protect the Track Switcher, and the Grand Dimension Crevice's roots won't stop...","TWN":"之前準備的線路轉換器果然沒能守住，大峽谷的根部應該不會停止……"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"우릴 지킬 결계가 깨지면, 앞으로 마주해야 할 건 지금까지와는 다른 붉은 하늘이겠지.","JPN":"我々を守ってくれる結界が破れたら、今までとは違う赤い空を目にすることになるだろう。","ENG":"When the barrier breaks, what awaits will be a different crimson sky than before.","TWN":"要是守護我們的結界被打破，之後要面臨的應該是和目前為止不一樣的紅色天空吧。"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"결국… 클리포트 게임이라는 악몽이 반복되겠군요.","JPN":"結局……クリフォトゲームという悪夢が繰り返されるんですね。","ENG":"In the end... the nightmare called the Qliphoth Game repeats.","TWN":"最後…逆卡巴拉遊戲這個惡夢應該會反覆出現。"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그래. 이러나저러나, 이후의 일은 최고 관리자에게 기댈 수밖에 없겠군.","JPN":"ああ。なんやかんや、後のことは最高管理者に頼るしかないな。","ENG":"Yes. One way or another, we'll have to rely on the Supreme Administrator now.","TWN":"是啊，不管怎樣，之後的事應該只能依靠最高管理者了。"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"부디, 그 자가 준비한 안배가…….","JPN":"どうか、彼の采配が……","ENG":"Let's hope the arrangements he prepared...","TWN":"只希望那個人的安排……"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"다시금 세상을 지키길 바랄 뿐이네.","JPN":"再び世界を守ってくれることを願うばかりだ。","ENG":"Will protect the world once more.","TWN":"能再次守住這個世界。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"……과연. 챔버의 상황은 파악했네.","JPN":"……なるほど。チェンバーの状況は把握した。","ENG":"...I see. I've grasped Chamber's situation.","TWN":"……果然掌握了密室的情況。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"죄송합니다. 큰 기대를 받았건만, 제 힘이 부족해 도시를 온전히 지켜내지 못했습니다.","JPN":"申し訳ありません。大きな期待を寄せていただいたにも関わらず、力及ばず都市を守りきれませんでした。","ENG":"My apologies. You expected much, but my power was lacking and I couldn't fully protect the city.","TWN":"抱歉，雖然大家對我寄予厚望，但我的力量不足，沒辦法完整守住城市。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"아, 아닙니다. 주군! 이번 일은, 순전히 제가 미숙했기에…….","JPN":"ち、違います、我が主！　今回の件は、私が未熟だったゆえ……","ENG":"N-no, Master! This was entirely my own inexperience...","TWN":"別、別這麼說，主君！這次的事純粹是因為我不成熟……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"챔버는 여섯 지부 중에서도 특히나 변수가 많던 도시야.","JPN":"チェンバーは6つの支部の中でも特に不確定要素が多かった都市だ。","ENG":"Chamber's always been the most volatile of the six branches.","TWN":"密室在六個分部當中也是變數特別多的城市。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"봉인전대인 고르디우스를 보낸 선택이 지금에 와서 잘못되었다고 생각되지는 않네.","JPN":"封印戦隊ゴルディウスを送り出すという選択は間違ってなかったと、今も思っている。","ENG":"I don't think sending the Gordias Seal Division was the wrong call, even now.","TWN":"事到如今，我不認為派封印戰隊哥帝爾斯的選擇是錯的。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"비록 도시를 지키지는 못했지만… 차원을 격리하는 봉인역의 힘으로 유예를 벌었으니 말이야.","JPN":"都市を守りきれなかったとはいえ……次元を隔離する封印域の力で時間稼ぎができるしね。","ENG":"We couldn't save the city... but the Domain isolating the dimension bought us a stay.","TWN":"儘管無法守住城市…卻以隔離次元的封印域力量暫緩了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"SANAE_NANA_NULL_PR","text":{"KOREA":"주인어른. 말씀은 감사합니다만, 이곳에 마련될 봉인역은 오롯이 나오님의 힘으로 만들어질 예정입니다.","JPN":"社長。ありがたいお言葉ですが、こちらの封印域は、完全にナオ様の力で作られる予定です。","ENG":"Master, thank you. But the Domain here will rely solely on Miss Nao's power.","TWN":"主人，謝謝你這麼說，但將在這裡建立的封印域，只會以奈緒的力量打造。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그래. 그 마저도 명부신의 영혼이 아닌 북방합의체의 그림자 핵을 통한 방법이지.","JPN":"ああ。それも冥府の神の魂ではなく、北方合意体のシャドウの核を利用した方法じゃ。","ENG":"Right. And not the Nether God's souls, but the Northern Union's Shadow Core.","TWN":"沒錯，就連這個也不是透過冥府神的靈魂，而是透過北方和議會暗影核心的方法。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"결계를 유지하는 영혼의 격이 낮은 이상, 이 방법으로는 오래 못 버틴다.","JPN":"結界を維持する魂の格が低い以上、この方法では長く持たん。","ENG":"With souls of such low grade maintaining it, the barrier won't last long.","TWN":"維持結界的靈魂級別較低，用這個方法沒辦法撐太久。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"다른 지부의 상황이 파악되고 있으니 곧 상황을 타개할 방법을 찾을 수 있을 걸세.","JPN":"他の支部の状況も把握中だから、もうじき打開策が見つかるさ。","ENG":"We're getting the other branches' status. Soon we'll find a way to break this stalemate.","TWN":"我們正在掌握其他分部的情況，應該很快就能找到解決辦法。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"무리한 부탁인 건 알지만… 그때까지 힘써줬으면 좋겠군.","JPN":"無理な頼みなのは承知しているが……それまで頑張ってくれ。","ENG":"I know it's a lot to ask, but... hold out until then.","TWN":"雖然我知道是無理的請求…但希望妳能幫忙到那個時候。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_PR","face":"UNIT_IDLE"}}}}]`);export{e as default};